// Clean RSS XML so n8n XML node can parse it reliably
let xml = $json.data;

xml = xml.replace(/(href|src|data-[a-zA-Z0-9_-]+)=([^" >]+)/g, '$1="$2"');
xml = xml.replace(/&(?!(amp|lt|gt|quot|apos|nbsp);)/g, '&amp;');
xml = xml.replace(/<!\[CDATA\[(.*?)\]\]>/gs, '$1');
xml = xml.replace(/<script[\s\S]*?<\/script>/gi, "");
xml = xml.replace(/<[^ >]+\/>/g, '');

return { xml };

const out = [];

function getValue(v) {
  if (Array.isArray(v)) return v[0];
  if (typeof v === "object") return Object.values(v).join("");
  return v || "";
}

const items = $json.rss?.channel?.item || [];

for (const item of items) {
  const title = getValue(item.title);
  const link = getValue(item.link);
  const summary = getValue(item.description);

  out.push({
    json: { title, link, summary }
  });
}

return out;

const out = [];

for (const item of $input.all()) {
  const { title, link, summary } = item.json;

  if (!title || !link) continue;

  // Build a payload that mimics the form submission fields
  out.push({
    json: {
      "Topic": title,
      "Keywords or Hashtags (Optional)": "#cybersecurity #onlinesafety #digitalsecurity",
      "Links": link,
      "OriginalSummary": summary || ""
    }
  });
}

return out;

// Sanitize RSS-derived fields to prevent HTML/script injection
// before they reach the LLM and end up in approval emails

function sanitize(str) {
  if (typeof str !== 'string') return str;
  return str
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<style[\s\S]*?<\/style>/gi, '')
    .replace(/<iframe[\s\S]*?<\/iframe>/gi, '')
    .replace(/<object[\s\S]*?<\/object>/gi, '')
    .replace(/<embed[\s\S]*?>/gi, '')
    .replace(/on\w+\s*=\s*["'][^"']*["']/gi, '')
    .replace(/on\w+\s*=\s*[^\s>]+/gi, '')
    .replace(/javascript\s*:/gi, '')
    .replace(/data\s*:\s*text\/html/gi, '');
}

const items = [];
for (const item of $input.all()) {
  items.push({
    json: {
      Topic: sanitize(item.json.Topic),
      'Keywords or Hashtags (Optional)': sanitize(item.json['Keywords or Hashtags (Optional)']),
      Links: sanitize(item.json.Links),
      OriginalSummary: sanitize(item.json.OriginalSummary)
    }
  });
}
return items;

// Reattach binary data from whichever path was taken
const isAutoRun = $('Is auto run?').item.json.data?.approved !== undefined 
  ? false  // Manual run went through approval
  : true;  // Auto run (cron)

let binaryData;

if (isAutoRun) {
  // Cron path: always uses AI-generated image
  binaryData = $('Generate an image').item.binary;
} else {
  // Manual form path: check user's choice
  const aiGenerated = $('Use AI?').item.json['Generate Custom Image using AI Image Generator'] === 'Yes';

  if (aiGenerated) {
    binaryData = $('Generate an image').item.binary;
  } else {
    binaryData = $('Rename Binary File').item.binary;
  }
}

// Get the current item (approval data)
const currentItem = $input.item;

// Attach the binary data to the current item
return {
  json: currentItem.json,
  binary: binaryData
};

// Sanitize LLM-generated HTML before inserting into approval email
// Removes dangerous elements while preserving email-safe formatting

let html = $json.output || '';

// Remove script/style/iframe/object/embed tags
html = html.replace(/<script[\s\S]*?<\/script>/gi, '');
html = html.replace(/<style[\s\S]*?<\/style>/gi, '');
html = html.replace(/<iframe[\s\S]*?<\/iframe>/gi, '');
html = html.replace(/<object[\s\S]*?<\/object>/gi, '');
html = html.replace(/<embed[\s\S]*?>/gi, '');

// Remove event handlers
html = html.replace(/\s+on\w+\s*=\s*["'][^"']*["']/gi, '');
html = html.replace(/\s+on\w+\s*=\s*[^\s>]+/gi, '');

// Remove javascript: and data: URIs
html = html.replace(/javascript\s*:/gi, '');
html = html.replace(/data\s*:\s*text\/html/gi, '');

// Remove code fences the LLM might have included
html = html.replace(/```html?/gi, '').replace(/```/g, '');

return { json: { ...$json, output: html } };
